def _detect_domain(title: str, domain: str) -> str:
    t = (title + " " + (domain or "")).lower()
    if any(k in t for k in ["access control", "account manag", "least priv", "session lock",
                             "session term", "remote access", "wireless", "mobile device",
                             "portable storage", "publicly accessible", "external system",
                             "authorized access", "transaction & function", "information flow",
                             "separation of duties", "logon attempt", "use notification",
                             "access rights", "access restriction", "identity management",
                             "access via untrust", "use control", "authorization enforce"]):
        return "access_control"
    if any(k in t for k in ["audit", "log", "accountability", "event logging",
                             "time stamp", "clock sync", "timestamps", "non-repudiation",
                             "auditable event", "audit storage"]):
        return "audit"
    if any(k in t for k in ["configuration", "baseline config", "change control",
                             "software usage", "user-install", "system change", "impact anal",
                             "least functionality", "nonessential", "application execution",
                             "hardening", "baseline"]):
        return "config_mgmt"
    if any(k in t for k in ["contingency", "continuity", "backup", "recovery",
                             "disaster", "alternate site", "telecom", "reconstitut",
                             "resilience", "restore availab", "rto", "rpo"]):
        return "continuity"
    if any(k in t for k in ["identif", "authenticat", "credential", "password",
                             "mfa", "multi-factor", "token", "biometric", "re-auth",
                             "replay-resistant", "identifier manage", "obscure feedback",
                             "proofing", "binding"]):
        return "iam"
    if any(k in t for k in ["incident", "breach notif", "event response", "reportable"]):
        return "incident"
    if any(k in t for k in ["maintenance", "nonlocal maintenance", "remote maintenance",
                             "equipment sanitiz"]):
        return "maintenance"
    if any(k in t for k in ["media", "sanitiz", "removable", "storage media",
                             "media handling", "media disposal"]):
        return "media"
    if any(k in t for k in ["physical", "facility", "environmental", "power equip",
                             "fire protect", "water damage", "emergency shut", "emergency light",
                             "cabling", "workstation security", "perimeter", "physical entry",
                             "secure area", "clean desk", "equipment siting", "off-premises",
                             "physical access", "prototype protect"]):
        return "physical"
    if any(k in t for k in ["security plan", "rules of behavior", "privacy plan",
                             "planning policy", "baseline select", "baseline tailor",
                             "architecture"]):
        return "planning"
    if any(k in t for k in ["program management", "program plan", "governance",
                             "mission", "business process", "authorization process",
                             "measures of performance", "risk management strategy",
                             "security groups", "threat awareness"]):
        return "program"
    if any(k in t for k in ["personnel", "workforce", "screening", "termination",
                             "access agreement", "sanction", "position risk", "hr security",
                             "employment", "background check", "background screen"]):
        return "personnel"
    if any(k in t for k in ["risk assessment", "risk analys", "risk management",
                             "vulnerability scan", "security categor", "criticality",
                             "risk response", "risk appetite", "risk toleran"]):
        return "risk"
    if any(k in t for k in ["acquisition", "development life cycle", "sdlc",
                             "developer", "unsupported system", "system document",
                             "allocation of resource", "acquisition process",
                             "engineering principles"]):
        return "acquisition"
    if any(k in t for k in ["boundary", "network", "transmission", "encrypt",
                             "cryptograph", "denial of service", "session authentic",
                             "dns", "voip", "mobile code", "process isolation",
                             "information at rest", "communications protect",
                             "network segment", "zone boundary", "segregat"]):
        return "protection"
    if any(k in t for k in ["integrity", "malware", "flaw remediation", "patch",
                             "spam", "monitoring", "alert", "advisori",
                             "input valid", "information management", "malicious code",
                             "system scanning", "unauthorized use"]):
        return "integrity"
    if any(k in t for k in ["supply chain", "supplier", "sbom", "provenance",
                             "acquisition strateg", "component authentic", "component disposal",
                             "notification agreement", "vendor", "third.party risk",
                             "outsourc"]):
        return "supply_chain"
    if any(k in t for k in ["privacy", "pii", "personal", "consent",
                             "data subject", "dpia", "pia", "pii principal",
                             "purpose limitation", "data minim", "right to",
                             "erasure", "portability", "lawful basis", "gdpr",
                             "anonymi", "pseudonym", "retention of pii"]):
        return "privacy"
    if any(k in t for k in ["training", "awareness", "education", "literacy",
                             "role-based risk", "insider threat awareness"]):
        return "training"
    if any(k in t for k in ["cloud", "saas", "paas", "iaas", "virtualiz",
                             "hypervisor", "tenant", "container", "vm hard"]):
        return "cloud"
    if any(k in t for k in ["vulnerability", "vuln", "penetration test", "pen test",
                             "technical vuln", "patch manag"]):
        return "vulnerability"
    if any(k in t for k in ["key management", "cryptograph", "cipher", "fips 140",
                             "cryptographic key", "pkcs", "certificate manag"]):
        return "crypto"
    if any(k in t for k in ["secure coding", "secure development", "secure design",
                             "threat model", "code review", "sast", "dast",
                             "software bill of materials", "sbom", "sdlc security"]):
        return "sdlc"
    if any(k in t for k in ["governance", "board", "executive", "policy review",
                             "charter", "risk posture", "regulatory compli"]):
        return "governance"
    return "default"


def _get_assess(title: str, domain: str) -> dict:
    key = _detect_domain(title, domain)
    return _ASSESS.get(key, _ASSESS["default"])


