def _gen_fedramp(ctrl_id, title, domain):
    m = re.match(r"FR-([A-Z]+)-", ctrl_id)
    family = _FR_FAMILIES.get(m.group(1) if m else "", "information security")
    return (
        f"{title}: FedRAMP requires cloud service providers (CSPs) to implement this "
        f"{family} control as part of achieving and maintaining FedRAMP authorization. "
        f"FedRAMP applies NIST SP 800-53 requirements with FedRAMP-specific parameter "
        f"values to ensure federal information is protected at the required baseline "
        f"(Low, Moderate, or High). Implementation must be documented in the System "
        f"Security Plan and validated by a Third-Party Assessment Organization (3PAO)."
    )


def _gen_iso27001(ctrl_id, title, domain, fw_label="ISO 27001:2022"):
    raw = ctrl_id.lstrip("A").lstrip(".").split(".")[0]
    sections = {"5": "organizational", "6": "people", "7": "physical", "8": "technological"}
    sec = sections.get(raw, "information security")
    return (
        f"{title}: {fw_label} requires organizations to establish {sec} controls addressing "
        f"{title.lower()}. This control is part of the Information Security Management System "
        f"(ISMS) and must be documented in the Statement of Applicability (SoA). "
        f"Evidence of implementation and effectiveness is required during ISO 27001 "
        f"certification audits and internal ISMS reviews."
    )


def _gen_cmmc(ctrl_id, title, domain):
    m = re.match(r"([A-Z]+)\.(L\d)-", ctrl_id)
    fam = m.group(1) if m else ""
    lvl = m.group(2) if m else "L2"
    fam_names = {
        "AC": "Access Control", "AT": "Awareness and Training",
        "AU": "Audit and Accountability", "CA": "Security Assessment",
        "CM": "Configuration Management", "IA": "Identification and Authentication",
        "IR": "Incident Response", "MA": "Maintenance",
        "MP": "Media Protection", "PE": "Physical Protection",
        "PS": "Personnel Security", "RA": "Risk Assessment",
        "SA": "System and Services Acquisition", "SC": "System and Communications Protection",
        "SI": "System and Information Integrity", "SR": "Supply Chain Risk Management",
    }
    fn = fam_names.get(fam, "information security")
    return (
        f"{title}: CMMC 2.0 {lvl} requires contractors handling Controlled Unclassified "
        f"Information (CUI) to implement this {fn} practice. This practice derives from "
        f"NIST SP 800-171 and must be implemented, documented, and evidence maintained "
        f"for CMMC assessment. Contractors must achieve {lvl} certification to be eligible "
        f"for DoD contracts requiring CUI protection at this level."
    )


def _gen_sp800171(ctrl_id, title, domain):
    prefix = ".".join(ctrl_id.split(".")[:2])
    fam = _SP800171_FAMILIES.get(prefix, "information security")
    return (
        f"{title}: NIST SP 800-171 Rev 3 requires non-federal organizations handling CUI "
        f"to implement this {fam} requirement. This control protects the confidentiality "
        f"of CUI in non-federal systems and organizations and is directly mapped to "
        f"NIST SP 800-53 controls. Implementation must be documented in the System "
        f"Security Plan and assessed by the system owner or a third party."
    )


def _gen_csf2(ctrl_id, title, domain):
    func_code = ctrl_id.split(".")[0] if "." in ctrl_id else ctrl_id[:2]
    func = _CSF2_FUNCTIONS.get(func_code, func_code)
    return (
        f"{title}: The NIST Cybersecurity Framework 2.0 {func} function requires "
        f"organizations to {title.rstrip('.').lower()}. CSF 2.0 is a risk-based framework "
        f"that organizations use to manage and reduce cybersecurity risk. This subcategory "
        f"supports the broader CSF outcome and should be implemented proportionate to the "
        f"organization's risk profile, sector requirements, and existing capabilities."
    )


def _gen_npf(ctrl_id, title, domain):
    func_code = ctrl_id.split(".")[0] if "." in ctrl_id else ctrl_id[:2]
    return (
        f"{title}: The NIST Privacy Framework requires organizations to {title.rstrip('.').lower()} "
        f"as part of the {func_code.replace('-P', '').title()} function. This subcategory "
        f"supports privacy risk management by addressing how organizations identify, govern, "
        f"control, communicate about, and protect privacy risks while enabling individuals "
        f"to exercise agency over their personal information."
    )


def _gen_ssdf(ctrl_id, title, domain):
    practice_code = ctrl_id.split(".")[0]
    practice = _SSDF_PRACTICES.get(practice_code, "secure software development")
    return (
        f"{title}: The NIST SSDF v1.1 {practice} practice requires software producers to "
        f"{title.rstrip('.').lower()}. SSDF provides a core set of secure software "
        f"development practices to reduce the number and severity of vulnerabilities in "
        f"released software. Each practice should be integrated into the organization's "
        f"SDLC and documented with evidence for supply chain assurance."
    )


def _gen_isa62443(ctrl_id, title, domain):
    m = re.match(r"(SR \d)", ctrl_id)
    req = _ISA_SR.get(m.group(1) if m else "", "security")
    return (
        f"{title}: ISA/IEC 62443-3-3 Security Requirement {ctrl_id} addresses {req.lower()} "
        f"for industrial automation and control systems (IACS). This security requirement "
        f"must be implemented at the appropriate Security Level (SL-C 1–4) based on "
        f"the risk assessment of the control system zone. Implementation applies to "
        f"control system components, network boundaries, and operator access paths."
    )


def _gen_iso27017(ctrl_id, title, domain):
    return (
        f"{title}: ISO/IEC 27017:2015 provides cloud-specific implementation guidance for "
        f"ISO 27001 controls. This control addresses {title.lower()} in cloud service "
        f"environments and applies to both cloud service providers (CSPs) and cloud "
        f"service customers (CSCs). The shared responsibility model must clearly delineate "
        f"which party is responsible for each aspect of this control's implementation."
    )


def _gen_iso27018(ctrl_id, title, domain):
    return (
        f"{title}: ISO/IEC 27018:2019 establishes controls for public cloud processors "
        f"handling personally identifiable information (PII). This control requires cloud "
        f"processors to {title.rstrip('.').lower()} in accordance with customer contracts "
        f"and applicable privacy regulations. Cloud processors must implement these controls "
        f"to provide transparent, auditable PII protection assurances to cloud customers."
    )


def _gen_iso27701(ctrl_id, title, domain):
    role = "Controller" if ctrl_id.startswith("7.") else "Processor"
    return (
        f"{title}: ISO/IEC 27701:2019 extends ISO 27001 with privacy-specific controls "
        f"for {role.lower()}s. This control requires {role.lower()}s to {title.rstrip('.').lower()} "
        f"as part of a Privacy Information Management System (PIMS). Implementation "
        f"must be documented in the PIMS scope, Statement of Applicability, and "
        f"demonstrated during ISO 27701 certification audits."
    )


