# ─── Main seeding logic ────────────────────────────────────────────────────────

import sqlite3, json, os, sys

def main():
    db_path = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "blacksite.db")
    if not os.path.exists(db_path):
        print(f"ERROR: DB not found at {db_path}", file=sys.stderr)
        sys.exit(1)

    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()

    total_updated = 0
    total_skipped = 0

    # ── Pass 1: SEED_DATA (specific frameworks) ──────────────────────────────
    print("=== Pass 1: Specific SEED_DATA ===")
    for fw_sn, ctrl_map in SEED_DATA.items():
        cur.execute(
            "SELECT id FROM compliance_frameworks WHERE short_name = ?", (fw_sn,)
        )
        fw_row = cur.fetchone()
        if not fw_row:
            print(f"  [WARN] Framework not found: {fw_sn}")
            continue
        fw_id = fw_row["id"]
        fw_updated = 0
        for ctrl_id, data in ctrl_map.items():
            desc = data.get("description", "")
            params = {k: data[k] for k in ("examine", "interview", "test") if k in data}
            params_json = json.dumps(params) if params else None
            # Only update rows that are missing description or parameters_json
            cur.execute(
                """UPDATE catalog_controls
                   SET description = ?,
                       parameters_json = ?
                   WHERE framework_id = ?
                     AND control_id = ?
                     AND (description IS NULL OR description = '' OR parameters_json IS NULL OR parameters_json = '')""",
                (desc, params_json, fw_id, ctrl_id),
            )
            if cur.rowcount > 0:
                fw_updated += cur.rowcount
            else:
                # Already seeded — skip silently
                total_skipped += 1
        print(f"  {fw_sn}: {fw_updated} controls updated")
        total_updated += fw_updated

    # ── Pass 2: Template generators ──────────────────────────────────────────
    print("\n=== Pass 2: Template generators ===")
    for fw_sn, gen_fn in _TEMPLATE_GENERATORS.items():
        cur.execute(
            """SELECT cc.id, cc.control_id, cc.title, cc.domain
               FROM catalog_controls cc
               JOIN compliance_frameworks cf ON cc.framework_id = cf.id
               WHERE cf.short_name = ?
                 AND (cc.description IS NULL OR cc.description = ''
                      OR cc.parameters_json IS NULL OR cc.parameters_json = '')""",
            (fw_sn,),
        )
        rows = cur.fetchall()
        if not rows:
            print(f"  {fw_sn}: nothing to seed")
            continue
        fw_updated = 0
        for row in rows:
            ctrl_id = row["control_id"]
            title   = row["title"] or ""
            domain  = row["domain"] or ""
            try:
                result = gen_fn(ctrl_id, title, domain)
            except Exception as e:
                print(f"  [WARN] {fw_sn}/{ctrl_id} generator error: {e}")
                continue
            # Generators return either a dict or a plain string (description only)
            if isinstance(result, dict):
                desc       = result.get("description", "")
                examine    = result.get("examine", [])
                interview  = result.get("interview", [])
                test_steps = result.get("test", [])
            else:
                desc = str(result)
                # Build generic assess arrays from domain template
                tmpl = _ASSESS.get(_detect_domain(title, domain),
                                   _ASSESS["default"])
                examine    = tmpl["examine"]
                interview  = tmpl["interview"]
                test_steps = tmpl["test"]
            params = {"examine": examine, "interview": interview, "test": test_steps}
            params_json = json.dumps(params)
            cur.execute(
                """UPDATE catalog_controls
                   SET description = ?,
                       parameters_json = ?
                   WHERE id = ?""",
                (desc, params_json, row["id"]),
            )
            fw_updated += 1
        print(f"  {fw_sn}: {fw_updated} controls updated")
        total_updated += fw_updated

    conn.commit()
    conn.close()

    print(f"\n✓ Done. {total_updated} controls updated, {total_skipped} already had content.")


if __name__ == "__main__":
    main()
